  const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#039;');
  const fmt = (v) => Number.isFinite(Number(v)) ? Number(Number(v).toPrecision(7)).toString() : String(v ?? '—');
  function finite(v,label){const n=Number(v);if(!Number.isFinite(n)) throw new Error(`${label} must be finite.`);return n;}
  function method(id){return CATALOG.methods.find((m)=>m.id===id)||null;}
  function normalizeInputs(def, supplied={}){const values={};for(const input of def.inputs){const n=finite(supplied[input.key] ?? input.default,input.label);if(input.min!==undefined && n<input.min) throw new Error(`${input.label} must be at least ${input.min}.`);if(input.max!==undefined && n>input.max) throw new Error(`${input.label} must be at most ${input.max}.`);values[input.key]=n;}return values;}
  function calculate(operation,a){
    switch(operation){
      case 'exponential_biomass': return a.x0 * Math.exp(a.mu * a.time);
      case 'specific_growth_rate': return Math.log(a.x2 / a.x1) / (a.t2 - a.t1);
      case 'doubling_time': return Math.log(2) / a.mu;
      case 'monod_growth_rate': return a.mu_max * a.substrate / (a.ks + a.substrate);
      case 'logistic_biomass': return a.carrying_capacity / (1 + ((a.carrying_capacity - a.x0) / a.x0) * Math.exp(-a.mu * a.time));
      case 'viable_cell_density': return a.total_cells * a.viability_percent / 100;
      case 'substrate_consumed': return a.initial_substrate - a.final_substrate;
      case 'biomass_yield': return a.biomass_increase / a.substrate_consumed;
      case 'product_yield': return a.product_formed / a.substrate_consumed;
      case 'batch_productivity': return a.product_concentration / a.batch_time;
      case 'maintenance_substrate': return a.maintenance_coefficient * a.biomass * a.time;
      case 'carbon_recovery': return a.carbon_outputs / a.carbon_inputs * 100;
      case 'feed_volume': return a.feed_rate * a.time;
      case 'fed_batch_final_volume': return a.initial_volume + a.feed_rate * a.time;
      case 'substrate_mass_fed': return a.feed_rate * a.feed_concentration * a.time;
      case 'exponential_feed_rate': return a.initial_feed_rate * Math.exp(a.mu_set * a.time);
      case 'apparent_dilution_rate': return a.feed_rate / a.reactor_volume;
      case 'fed_batch_substrate_balance': return a.initial_substrate_mass + a.substrate_fed - a.substrate_consumed;
      case 'dilution_rate': return a.flow_rate / a.reactor_volume;
      case 'residence_time': return a.reactor_volume / a.flow_rate;
      case 'chemostat_biomass': return a.yield_coefficient * (a.feed_substrate - a.residual_substrate);
      case 'washout_margin': return a.mu_max - a.dilution_rate;
      case 'continuous_productivity': return a.dilution_rate * a.product_concentration;
      case 'critical_dilution_monod': return a.mu_max * a.feed_substrate / (a.ks + a.feed_substrate);
      case 'oxygen_transfer_rate': return a.kla * (a.saturation_concentration - a.liquid_concentration);
      case 'oxygen_uptake_rate': return a.specific_oxygen_uptake * a.biomass;
      case 'kla_from_otr': return a.otr / (a.saturation_concentration - a.liquid_concentration);
      case 'oxygen_balance_margin': return a.otr - a.our;
      case 'aeration_vvm': return a.gas_flow / a.reactor_volume;
      case 'gas_molar_flow': return a.volumetric_flow * a.pressure / (0.082057 * a.temperature);
      case 'metabolic_heat': return a.heat_per_biomass * a.biomass_rate;
      case 'cooling_water_flow': return a.heat_duty / (a.heat_capacity * a.temperature_rise);
      case 'impeller_tip_speed': return Math.PI * a.impeller_diameter * a.rotation_speed / 60;
      case 'power_per_volume': return a.power / a.volume;
      case 'reynolds_mixing': return a.density * a.rotation_speed * (a.impeller_diameter ** 2) / a.dynamic_viscosity;
      case 'mixing_time_correlation': return a.coefficient * ((a.volume / a.power) ** a.exponent);
      case 'geometric_scale_factor': return a.target_volume / a.base_volume;
      case 'linear_scale_factor': return (a.target_volume / a.base_volume) ** (1 / 3);
      case 'constant_tip_speed_rpm': return a.base_rpm * a.base_diameter / a.target_diameter;
      case 'constant_power_volume': return a.base_power * a.target_volume / a.base_volume;
      case 'cylinder_area_volume': return (Math.PI * a.diameter * a.height + 2 * Math.PI * ((a.diameter / 2) ** 2)) / (Math.PI * ((a.diameter / 2) ** 2) * a.height);
      case 'superficial_gas_velocity': return a.gas_flow / a.cross_section_area;
      case 'luedeking_piret_product': return (a.alpha * a.mu + a.beta) * a.biomass * a.time;
      case 'specific_productivity': return a.product_rate / a.biomass;
      case 'harvest_titer': return a.product_mass / a.harvest_volume;
      case 'downstream_recovery': return a.recovered_mass / a.feed_mass * 100;
      case 'volumetric_productivity': return a.product_mass / (a.reactor_volume * a.process_time);
      case 'overall_process_yield': return a.final_product_mass / a.theoretical_product_mass * 100;
      default: throw new Error(`Unsupported bioprocess operation: ${operation}`);
    }
  }
  function run(methodId, supplied={}){const def=method(methodId);if(!def) throw new Error(`Unknown bioprocess method: ${methodId}`);const inputs=normalizeInputs(def,supplied);if(def.operation==='specific_growth_rate' && inputs.t2===inputs.t1) throw new Error('Final time must differ from initial time.');if(['substrate_consumed'].includes(def.operation) && inputs.final_substrate>inputs.initial_substrate) throw new Error('Final substrate cannot exceed initial substrate for this depletion estimate.');if(['kla_from_otr'].includes(def.operation) && inputs.saturation_concentration===inputs.liquid_concentration) throw new Error('Oxygen driving force must be non-zero.');const result=calculate(def.operation,inputs);if(!Number.isFinite(result)) throw new Error('Calculation produced a non-finite result.');return {schema:'sc-lab-biotechnology-bioprocess-result/1.0',version:VERSION,methodId:def.id,title:def.title,category:def.category,formula:def.formula,inputs,outputs:{result},outputDefinition:def.outputs.result,warnings:[],audit:{createdAt:new Date().toISOString(),engine:'sc-lab-bioprocess-browser',release:VERSION}};}
  function runBenchmarks(){return CATALOG.benchmarks.map((b)=>{try{const actual=run(b.methodId,b.inputs).outputs.result;const error=Math.abs(actual-b.expected.result);return {methodId:b.methodId,passed:error<=b.tolerance*Math.max(1,Math.abs(b.expected.result)),actual,expected:b.expected.result,error};}catch(error){return {methodId:b.methodId,passed:false,error:String(error.message||error)};}});}
  function parseCsvLine(line){const cells=[];let current='';let quoted=false;for(let i=0;i<line.length;i+=1){const c=line[i];if(c==='"'){if(quoted&&line[i+1]==='"'){current+='"';i+=1;}else quoted=!quoted;}else if(c===','&&!quoted){cells.push(current.trim());current='';}else current+=c;}cells.push(current.trim());return cells;}
  function parseCsv(text){const lines=String(text).replaceAll('\r\n','\n').replaceAll('\r','\n').split('\n').filter((line)=>line.trim()!=='');if(!lines.length)return[];const headers=parseCsvLine(lines[0]);return lines.slice(1).map((line,index)=>{const cells=parseCsvLine(line);const row={__row:index+2};headers.forEach((h,i)=>row[h]=cells[i]??'');return row;});}
  function batchRun(methodId,text){const def=method(methodId);if(!def)throw new Error('Unknown method.');const rows=parseCsv(text);if(!rows.length)throw new Error('At least one CSV row is required.');const results=rows.map((row,index)=>{const sample=String(row.sample||`sample-${index+1}`);try{return {sample,ok:true,analysis:run(methodId,row)};}catch(error){return {sample,ok:false,error:String(error.message||error)};}});const values=results.filter((r)=>r.ok).map((r)=>r.analysis.outputs.result);const mean=values.length?values.reduce((a,b)=>a+b,0)/values.length:null;const sd=values.length>1?Math.sqrt(values.reduce((sum,v)=>sum+((v-mean)**2),0)/(values.length-1)):0;const cv=mean===null||mean===0?null:Math.abs(sd/mean)*100;return {schema:'sc-lab-bioprocess-batch/1.0',version:VERSION,methodId,rowCount:results.length,successCount:values.length,errorCount:results.length-values.length,results,statistics:{n:values.length,mean,standardDeviation:sd,coefficientOfVariationPercent:cv,minimum:values.length?Math.min(...values):null,maximum:values.length?Math.max(...values):null},flags:[...(cv!==null&&cv>20?['Coefficient of variation exceeds 20%.']:[]),...(results.length-values.length?[`${results.length-values.length} row(s) failed.`]:[])],audit:{createdAt:new Date().toISOString(),engine:'sc-lab-bioprocess-batch-browser',release:VERSION}};}
  function simulateBatch(p={}){const x0=finite(p.x0??1,'Initial biomass'),mu=finite(p.mu??0.3,'Growth rate'),time=finite(p.time??24,'Time'),s0=finite(p.substrate0??40,'Initial substrate'),yieldXs=finite(p.yieldXs??0.5,'Biomass yield'),yieldPs=finite(p.yieldPs??0.2,'Product yield'),steps=40;const points=[];for(let i=0;i<=steps;i+=1){const t=time*i/steps;const ideal=x0*Math.exp(mu*t);const maxBiomass=x0+s0*yieldXs;const biomass=Math.min(ideal,maxBiomass);const substrate=Math.max(0,s0-(biomass-x0)/yieldXs);const product=(s0-substrate)*yieldPs;points.push({time:t,biomass,substrate,product});}return {mode:'batch',points,summary:points.at(-1)};}
  function simulateFedBatch(p={}){const v0=finite(p.initialVolume??5,'Initial volume'),f0=finite(p.initialFeedRate??0.05,'Initial feed rate'),mu=finite(p.muSet??0.15,'Target growth rate'),cf=finite(p.feedConcentration??500,'Feed concentration'),x0=finite(p.x0??2,'Initial biomass'),time=finite(p.time??24,'Time'),steps=40;const points=[];let cumulativeFeed=0;for(let i=0;i<=steps;i+=1){const t=time*i/steps;const feedRate=f0*Math.exp(mu*t);cumulativeFeed=i===0?0:f0/mu*(Math.exp(mu*t)-1);const volume=v0+cumulativeFeed;const biomass=x0*Math.exp(mu*t)*v0/volume;points.push({time:t,feedRate,volume,biomass,substrateFed:cumulativeFeed*cf});}return {mode:'fed-batch',points,summary:points.at(-1)};}
  function simulateContinuous(p={}){const volume=finite(p.volume??10,'Volume'),flow=finite(p.flowRate??1.5,'Flow rate'),muMax=finite(p.muMax??0.5,'Maximum growth rate'),ks=finite(p.ks??0.5,'Ks'),sf=finite(p.feedSubstrate??20,'Feed substrate'),yieldXs=finite(p.yieldXs??0.5,'Yield'),product=finite(p.productConcentration??12,'Product concentration');const D=flow/volume;const washout=D>=muMax;const residual=washout?sf:Math.min(sf,ks*D/(muMax-D));const biomass=washout?0:yieldXs*(sf-residual);return {mode:'continuous',points:[{label:'Steady state',dilutionRate:D,residualSubstrate:residual,biomass,productivity:D*product,washoutMargin:muMax-D}],summary:{dilutionRate:D,residualSubstrate:residual,biomass,productivity:D*product,washoutMargin:muMax-D,washout}};}
  function simulate(mode,p){if(mode==='batch')return simulateBatch(p);if(mode==='fed-batch')return simulateFedBatch(p);if(mode==='continuous')return simulateContinuous(p);throw new Error(`Unknown simulation mode: ${mode}`);}
  function saveLocal(key,record){try{const rows=JSON.parse(W.localStorage?.getItem(key)||'[]');rows.unshift(record);W.localStorage?.setItem(key,JSON.stringify(rows.slice(0,100)));return true;}catch(_e){return false;}}
  function download(name,type,content){const blob=new Blob([content],{type});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=name;a.click();W.setTimeout(()=>URL.revokeObjectURL(url),500);}
  function chart(host,sim){if(sim.mode==='continuous'){const s=sim.summary;host.innerHTML=`<div class="sc-bpe-summary-grid">${Object.entries(s).map(([k,v])=>`<article><span>${esc(k)}</span><strong>${esc(fmt(v))}</strong></article>`).join('')}</div>`;return;}const series=['biomass',...(sim.mode==='batch'?['substrate','product']:['volume','feedRate'])];const pts=sim.points;const width=760,height=360,m={l:62,r:22,t:24,b:52};const all=series.flatMap((k)=>pts.map((p)=>Number(p[k])));const ymax=Math.max(...all,1);const xmax=Math.max(...pts.map((p)=>p.time),1);const x=(v)=>m.l+(v/xmax)*(width-m.l-m.r);const y=(v)=>m.t+(height-m.t-m.b)-(v/ymax)*(height-m.t-m.b);const paths=series.map((k,si)=>`<path class="sc-bpe-line sc-bpe-series-${si+1}" d="${pts.map((p,i)=>`${i?'L':'M'} ${x(p.time)} ${y(p[k])}`).join(' ')}"/>`).join('');host.innerHTML=`<div class="sc-bpe-chart-scroll"><svg viewBox="0 0 ${width} ${height}" role="img" aria-label="${esc(sim.mode)} process simulation"><line x1="${m.l}" y1="${height-m.b}" x2="${width-m.r}" y2="${height-m.b}" class="sc-bpe-axis"/><line x1="${m.l}" y1="${m.t}" x2="${m.l}" y2="${height-m.b}" class="sc-bpe-axis"/>${paths}<text x="${width/2}" y="${height-12}" class="sc-bpe-axis-label">Time</text></svg></div><div class="sc-bpe-legend">${series.map((k,i)=>`<span><i class="sc-bpe-series-${i+1}"></i>${esc(k)}</span>`).join('')}</div>`;}
  function ensureRoot(){let root=document.querySelector(ROOT_SELECTOR);if(root)return root;const panel=document.querySelector(`[data-lab-module="${MODULE_ID}"],[data-module-panel="${MODULE_ID}"]`);if(!panel)return null;root=document.createElement('div');root.setAttribute('data-biotechnology-bioprocess-root','');panel.appendChild(root);return root;}
  function render(root){if(root.dataset.scBpeVersion===VERSION&&root.children.length)return;const categories=CATALOG.categories;root.innerHTML=`<section class="sc-bpe-shell"><header class="sc-bpe-header"><div><p class="sc-bpe-kicker">LAB/BIOTECHNOLOGY/BIOPROCESS</p><h3>Biotechnology and Bioprocess Engineering</h3><p>Model biological production systems, reactor operation, oxygen transfer, scale-up, and downstream performance with auditable calculations and process simulations.</p></div><span>v${VERSION}</span></header><div class="sc-bpe-tabs"><button class="is-active" data-bpe-tab="calculator">Method calculator</button><button data-bpe-tab="simulation">Process simulation</button><button data-bpe-tab="batch">Batch and monitoring</button></div><section data-bpe-workspace="calculator" class="sc-bpe-workspace"><div class="sc-bpe-controls"><label><span>Category</span><select data-bpe-category>${categories.map((c)=>`<option>${esc(c)}</option>`).join('')}</select></label><label><span>Method</span><select data-bpe-method></select></label></div><div data-bpe-method-info></div><div class="sc-bpe-input-grid" data-bpe-inputs></div><div class="sc-bpe-actions"><button class="sc-bpe-primary" data-bpe-run>Calculate</button><button data-bpe-save disabled>Save to project</button><button data-bpe-provenance disabled>Create provenance record</button><button data-bpe-export disabled>Export JSON</button></div><p data-bpe-status aria-live="polite"></p><div data-bpe-result></div></section><section data-bpe-workspace="simulation" class="sc-bpe-workspace" hidden><div class="sc-bpe-controls"><label><span>Reactor mode</span><select data-bpe-sim-mode><option value="batch">Batch</option><option value="fed-batch">Fed-batch</option><option value="continuous">Continuous</option></select></label></div><div class="sc-bpe-input-grid" data-bpe-sim-inputs></div><div class="sc-bpe-actions"><button class="sc-bpe-primary" data-bpe-sim-run>Run simulation</button><button data-bpe-sim-export disabled>Export simulation</button></div><p data-bpe-sim-status></p><div data-bpe-chart></div></section><section data-bpe-workspace="batch" class="sc-bpe-workspace" hidden><div class="sc-bpe-controls"><label><span>Batch method</span><select data-bpe-batch-method>${CATALOG.methods.map((m)=>`<option value="${esc(m.id)}">${esc(m.category)} — ${esc(m.title)}</option>`).join('')}</select></label></div><label class="sc-bpe-csv"><span>CSV samples</span><textarea rows="10" data-bpe-csv spellcheck="false"></textarea></label><div class="sc-bpe-actions"><button class="sc-bpe-primary" data-bpe-batch-run>Run batch</button><button data-bpe-template>Load sample CSV</button><button data-bpe-batch-export disabled>Export batch JSON</button></div><p data-bpe-batch-status></p><div data-bpe-batch-result></div></section><aside class="sc-bpe-boundary"><strong>Engineering-use boundary</strong> Results are transparent computational estimates for research, education, and process planning. They do not replace controlled bioprocess procedures, biosafety review, validated manufacturing systems, regulatory qualification, or professional engineering judgment.</aside></section>`;
    const tabs=root.querySelectorAll('[data-bpe-tab]'),spaces=root.querySelectorAll('[data-bpe-workspace]');tabs.forEach((b)=>b.addEventListener('click',()=>{tabs.forEach((x)=>x.classList.toggle('is-active',x===b));spaces.forEach((s)=>s.hidden=s.dataset.bpeWorkspace!==b.dataset.bpeTab);}));
    const cat=root.querySelector('[data-bpe-category]'),sel=root.querySelector('[data-bpe-method]'),info=root.querySelector('[data-bpe-method-info]'),inputs=root.querySelector('[data-bpe-inputs]'),status=root.querySelector('[data-bpe-status]'),result=root.querySelector('[data-bpe-result]'),save=root.querySelector('[data-bpe-save]'),prov=root.querySelector('[data-bpe-provenance]'),exp=root.querySelector('[data-bpe-export]');
    function refreshMethods(){const rows=CATALOG.methods.filter((m)=>m.category===cat.value);sel.innerHTML=rows.map((m)=>`<option value="${esc(m.id)}">${esc(m.title)}</option>`).join('');refreshInputs();}
    function refreshInputs(){const def=method(sel.value);if(!def)return;info.innerHTML=`<article class="sc-bpe-method-card"><h4>${esc(def.title)}</h4><p>${esc(def.description)}</p><code>${esc(def.formula)}</code></article>`;inputs.innerHTML=def.inputs.map((i)=>`<label><span>${esc(i.label)}</span><input type="number" step="any" value="${esc(i.default)}" data-bpe-input="${esc(i.key)}"/><small>${esc(i.unit)}</small></label>`).join('');state.current=null;result.innerHTML='';[save,prov,exp].forEach((b)=>b.disabled=true);}
    cat.addEventListener('change',refreshMethods);sel.addEventListener('change',refreshInputs);root.querySelector('[data-bpe-run]').addEventListener('click',()=>{try{const values=Object.fromEntries(Array.from(root.querySelectorAll('[data-bpe-input]')).map((i)=>[i.dataset.bpeInput,i.value]));state.current=run(sel.value,values);result.innerHTML=`<article class="sc-bpe-result-card"><span>${esc(state.current.outputDefinition.label)}</span><strong>${esc(fmt(state.current.outputs.result))} ${esc(state.current.outputDefinition.unit)}</strong><code>${esc(state.current.formula)}</code></article>`;status.textContent='Calculation completed.';[save,prov,exp].forEach((b)=>b.disabled=false);}catch(e){status.textContent=String(e.message||e);}});
    save.addEventListener('click',()=>{if(state.current)status.textContent=saveLocal('sc-lab:project-analyses',state.current)?'Saved to project records.':'Storage unavailable.';});exp.addEventListener('click',()=>{if(state.current)download(`bioprocess-result-${Date.now()}.json`,'application/json',JSON.stringify(state.current,null,2));});prov.addEventListener('click',async()=>{if(!state.current)return;const api=Lab.MolecularAnalysisValidationProvenance;if(api?.createProvenanceRecord){const record=await api.createProvenanceRecord(state.current,{eventType:'bioprocess-calculation',methodId:state.current.methodId},null);saveLocal('sc-lab:molecular-provenance-ledger',record);status.textContent=`Provenance record ${record.recordId} created.`;}else status.textContent='v0.21.3 provenance engine is unavailable.';});
    const simMode=root.querySelector('[data-bpe-sim-mode]'),simInputs=root.querySelector('[data-bpe-sim-inputs]'),simStatus=root.querySelector('[data-bpe-sim-status]'),chartHost=root.querySelector('[data-bpe-chart]'),simExport=root.querySelector('[data-bpe-sim-export]');const simDefs={batch:[['x0','Initial biomass',1],['mu','Growth rate',0.3],['time','Time',24],['substrate0','Initial substrate',40],['yieldXs','Biomass yield',0.5],['yieldPs','Product yield',0.2]],'fed-batch':[['initialVolume','Initial volume',5],['initialFeedRate','Initial feed rate',0.05],['muSet','Target growth rate',0.15],['feedConcentration','Feed concentration',500],['x0','Initial biomass',2],['time','Time',24]],continuous:[['volume','Volume',10],['flowRate','Flow rate',1.5],['muMax','Maximum growth rate',0.5],['ks','Ks',0.5],['feedSubstrate','Feed substrate',20],['yieldXs','Biomass yield',0.5],['productConcentration','Product concentration',12]]};function refreshSim(){simInputs.innerHTML=simDefs[simMode.value].map(([k,l,d])=>`<label><span>${esc(l)}</span><input type="number" step="any" value="${d}" data-bpe-sim-input="${k}"/></label>`).join('');chartHost.innerHTML='';simExport.disabled=true;}simMode.addEventListener('change',refreshSim);root.querySelector('[data-bpe-sim-run]').addEventListener('click',()=>{try{const p=Object.fromEntries(Array.from(root.querySelectorAll('[data-bpe-sim-input]')).map((i)=>[i.dataset.bpeSimInput,i.value]));state.simulation=simulate(simMode.value,p);chart(chartHost,state.simulation);simStatus.textContent='Simulation completed.';simExport.disabled=false;}catch(e){simStatus.textContent=String(e.message||e);}});simExport.addEventListener('click',()=>{if(state.simulation)download(`bioprocess-simulation-${Date.now()}.json`,'application/json',JSON.stringify(state.simulation,null,2));});
    const batchSel=root.querySelector('[data-bpe-batch-method]'),csv=root.querySelector('[data-bpe-csv]'),batchStatus=root.querySelector('[data-bpe-batch-status]'),batchHost=root.querySelector('[data-bpe-batch-result]'),batchExport=root.querySelector('[data-bpe-batch-export]');function template(){const def=method(batchSel.value);const header=['sample',...def.inputs.map((i)=>i.key)].join(',');const rows=[1,2,3].map((n)=>[`sample-${n}`,...def.inputs.map((i)=>Number(i.default)*(n===1?1:n===2?1.02:0.98))].join(','));csv.value=[header,...rows].join('\n');}batchSel.addEventListener('change',template);root.querySelector('[data-bpe-template]').addEventListener('click',template);root.querySelector('[data-bpe-batch-run]').addEventListener('click',()=>{try{state.batch=batchRun(batchSel.value,csv.value);batchStatus.textContent=`${state.batch.successCount} of ${state.batch.rowCount} rows calculated.${state.batch.flags.length?' Review flags present.':''}`;batchHost.innerHTML=`<div class="sc-bpe-summary-grid">${Object.entries(state.batch.statistics).map(([k,v])=>`<article><span>${esc(k)}</span><strong>${esc(fmt(v))}</strong></article>`).join('')}</div><div class="sc-bpe-table-scroll"><table><thead><tr><th>Sample</th><th>Status</th><th>Result</th><th>Notes</th></tr></thead><tbody>${state.batch.results.map((r)=>`<tr><th>${esc(r.sample)}</th><td>${r.ok?'Calculated':'Error'}</td><td>${r.ok?esc(fmt(r.analysis.outputs.result)):'—'}</td><td>${r.ok?'':esc(r.error)}</td></tr>`).join('')}</tbody></table></div>`;batchExport.disabled=false;}catch(e){batchStatus.textContent=String(e.message||e);}});batchExport.addEventListener('click',()=>{if(state.batch)download(`bioprocess-batch-${Date.now()}.json`,'application/json',JSON.stringify(state.batch,null,2));});
    refreshMethods();refreshSim();template();root.dataset.scBpeVersion=VERSION;state.initializedAt=new Date().toISOString();
  }
  function init(){if(typeof document==='undefined')return false;const root=ensureRoot();if(!root){state.lastError='Bioprocess workspace mount unavailable.';return false;}try{render(root);state.lastError=null;return true;}catch(e){state.lastError=String(e.message||e);return false;}}
  function status(){const root=typeof document!=='undefined'?document.querySelector(ROOT_SELECTOR):null;return {version:VERSION,methodCount:CATALOG.methods.length,benchmarkCount:CATALOG.benchmarks.length,categoryCount:CATALOG.categories.length,rootFound:Boolean(root),rendered:Boolean(root?.querySelector('.sc-bpe-shell')),currentMethodId:state.current?.methodId||null,simulationMode:state.simulation?.mode||null,lastError:state.lastError,initializedAt:state.initializedAt};}
