  if(typeof document!=='undefined'){const start=()=>{[0,80,220,600,1400].forEach((d)=>W.setTimeout(init,d));document.addEventListener('sc-lab:module-opened',init);if(typeof MutationObserver!=='undefined'){new MutationObserver(()=>{if(!document.querySelector(ROOT_SELECTOR))init();}).observe(document.documentElement,{childList:true,subtree:true});}};document.readyState==='loading'?document.addEventListener('DOMContentLoaded',start,{once:true}):start();}
